@module modalHost  src=modalHost.lua  loc=151  sha=d013d39  mode=chunk  self=modalHost
@deps ctx, chrome

# Invariants & contracts
  @invariant  one modalHost per coordinator; threaded into every page that opens modals
  @invariant  state.kind picks the render; built-ins are 'prompt' and 'confirm'; pages register custom kinds at load time

# Shapes
  @shape  state = { kind, title, callback?, onClose?, flags?, ... per-kind fields }

# Imports
  @require ImGui = 'imgui'  @ 7
      @contract  render(state, close) draws inside an active BeginPopupModal; close(invoke, ...args) captures+clears state, closes popup, pcalls callback if invoke, then pcalls onClose unconditionally

# Private state
  @state POPUP_ID = '###modalHost'  @ 12
  @state kinds = {}  @ 14
  @state state = nil  @ 15
  @state wasOpen = false  @ 16   -- snapshot at tick(); stays true across the closing frame
  @state modalHost = {}  @ 20

# Private functions
  @fn label()  @ 18

# Public API (modalHost:*)
  @api modalHost:registerKind(kind, render)  @ 22
  @api modalHost:open(s)  @ 24-27
  @api modalHost:openPrompt(args)  @ 29-39
  @api modalHost:openConfirm(args)  @ 41-48
  @api modalHost:isOpen()  @ 50
  @api modalHost:wasOpenAtFrameStart()  @ 51
  @api modalHost:tick()  @ 53
  @api modalHost:draw()  @ 55-102

# Uses (outbound edges)
  @use call    chrome.colour  @ draw:67
  @use call    chrome.popChromeWindow  @ draw:101
  @use call    chrome.pushChromeWindow  @ draw:65
  @use call    imgui.BeginPopupModal  @ draw:74
  @use call    imgui.CloseCurrentPopup  @ draw:83
  @use call    imgui.EndPopup  @ draw:95
  @use call    imgui.GetStyleVar  @ draw:71
  @use call    imgui.GetWindowViewport  @ draw:62
  @use call    imgui.InputText  @ 128,139
  @use call    imgui.IsKeyPressed  @ 108,110,132,133,135,143
  @use call    imgui.IsPopupOpen  @ draw:59
  @use call    imgui.IsWindowAppearing  @ 116
  @use call    imgui.OpenPopup  @ open:26 draw:60
  @use call    imgui.PopStyleColor  @ draw:100
  @use call    imgui.PopStyleVar  @ draw:75,99
  @use call    imgui.PushStyleColor  @ draw:67
  @use call    imgui.PushStyleVar  @ draw:68,72
